                itemOnPress(value);
              },
              showIcon: true,
              hideBorder: true,
              title: value.idTitle?.text,
              description: value.idText?.text,
              icon: value.idIcone?.text,
              priority: Number(value.idPriority?.text) || 0,
              showTagLabel: !!value?.idTagCard?.text,
              textTagLabel: capitalizeFirstLetters(value?.idTagCard?.text),
              typeTagLabel: 'neutral',
              highlightTagLabel: !!value?.idTagCard?.text,
            } as PropsCardActivityExtended)
        )
        .sort((a, b) => (a.priority ?? 0) - (b.priority ?? 0)),
    [benefits, itemOnPress]
  );

  return (
    <FlatList
      data={benefitList}
      keyExtractor={(item) => item.priority.toString()}
      renderItem={({ item }) => {
        return <CardActivity {...item} />;
      }}
    />
  );
};
