  <HeaderDS {...rest} />
)).attrs(() => {
  return {
    isHome: false,
  } as HeaderDS['props'];
})``;

export const ContainerHeader = styled(Box).attrs(() => {
  return {
    bgColor: theme.colors.LIGHT_BASE_01,
    justify: 'flex-end',
  } as Box['props'];
})``;

